type token = TIdent of string | TInt of int | TPct of int | TLArrow | TRArrow | TLParen | TRParen | TLBrace | TRBrace | TComma | TUnderscore | THash of string | TLiteral of string | TEOF | TMint
let dump_tok t = match t with TIdent s -> print_endline ("IDENT  " ^ s) | TInt n -> print_endline ("INT    " ^ string_of_int n) | TPct p -> print_endline ("PCT    " ^ string_of_int p) | TLArrow -> print_endline "LARROW" | TRArrow -> print_endline "RARROW" | TLParen -> print_endline "LPAREN" | TRParen -> print_endline "RPAREN" | TLBrace -> print_endline "LBRACE" | TRBrace -> print_endline "RBRACE" | TComma -> print_endline "COMMA" | TUnderscore -> print_endline "USCORE" | THash s -> print_endline ("HASH   " ^ s) | TLiteral s -> print_endline ("LIT    " ^ s) | TEOF -> print_endline "EOF" | TMint -> print_endline "MINT"
let rec dump_tokens toks = if is_empty toks then () else let _ = dump_tok (hd toks) in dump_tokens (tl toks)
let _ = dump_tokens [TMint; TIdent "coord2"; TRArrow; TLParen; TIdent "x"; TIdent "y"; TRParen; TLArrow; TInt 3; TComma; TInt 9; TLiteral "if"; TUnderscore; THash "comment text"; TEOF]
